import os, base64
base = os.path.expanduser("~/Desktop/RosterPayAU")
files = {}
files["src/utils/taxCalc.ts"] = ""
files["src/utils/wageHistory.ts"] = ""
files["src/utils/leaveCalc.ts"] = ""
files["src/utils/rosterUtils.ts"] = ""
files["src/utils/payCalc.ts"] = ""
files["src/constants/allowanceCatalog.ts"] = ""
files["src/hooks/useMonthData.ts"] = ""
files["src/store/index.ts"] = ""
files["app/_layout.tsx"] = ""
files["app/(tabs)/_layout.tsx"] = ""
for path, enc in files.items():
    full = os.path.join(base, path)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    with open(full, "wb") as fh:
        fh.write(base64.b64decode(enc))
    print(f"✅ {path}")
print("\n✅ All done!")